import { useRef } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function AutoBlurSearch({ query, onChange, children }: { query: string; onChange: (q: string) => void; children: React.ReactNode }) {
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);
  const isTouch = useMediaQuery('(pointer: coarse)', true);

  const onScroll = () => {
    if (!isTouch) return;
    if (document.activeElement === inputRef.current) {
      inputRef.current?.blur();
    }
  };

  return (
    <div className="flex flex-col h-dvh">
      <div
        className="sticky top-0 z-10 bg-white border-b p-3"
        style={{ paddingTop: 'max(0.75rem, env(safe-area-inset-top))' }}
      >
        <input
          ref={inputRef}
          type="search"
          value={query}
          onChange={(e) => onChange(e.target.value)}
          placeholder="Search"
          aria-label="Search"
          enterKeyHint="search"
          className="w-full min-h-11 rounded-lg border bg-neutral-50 px-3 text-base"
        />
      </div>
      <div
        ref={listRef}
        onScroll={onScroll}
        className="flex-1 overflow-y-auto"
      >
        {children}
      </div>
    </div>
  );
}

