// components/Lightbox.tsx
import { useEffect } from 'react';
import { ChevronLeft, ChevronRight, X } from 'lucide-react';

export function Lightbox({ open, image, onClose, onNext, onPrev }: { open: boolean; image: { src: string; alt: string }; onClose: () => void; onNext: () => void; onPrev: () => void }) {
  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
      if (e.key === 'ArrowRight') onNext();
      if (e.key === 'ArrowLeft') onPrev();
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose, onNext, onPrev]);

  if (!open) return null;
  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label={image.alt}
      className="
        fixed inset-0 z-50 bg-black
        flex items-center justify-center
        portrait:flex-col landscape:flex-row
      "
    >
      <img src={image.src} alt={image.alt} className="max-h-full max-w-full object-contain" />

      {/* Close button — always top-right with safe area */}
      <button
        type="button"
        onClick={onClose}
        aria-label="Close"
        className="absolute z-10 flex h-12 w-12 items-center justify-center rounded-full bg-white/10 text-white backdrop-blur"
        style={{
          top: 'max(1rem, env(safe-area-inset-top))',
          right: 'max(1rem, env(safe-area-inset-right))',
        }}
      ><X className="h-5 w-5" /></button>

      {/* Prev/Next — portrait: bottom; landscape: sides */}
      <button
        type="button"
        onClick={onPrev}
        aria-label="Previous"
        className="
          absolute z-10 flex h-12 w-12 items-center justify-center rounded-full bg-white/10 text-white backdrop-blur
          portrait:bottom-[max(1.5rem,env(safe-area-inset-bottom))] portrait:left-[10%]
          landscape:left-[max(1rem,env(safe-area-inset-left))] landscape:top-1/2 landscape:-translate-y-1/2
        "
      ><ChevronLeft className="h-5 w-5" /></button>
      <button
        type="button"
        onClick={onNext}
        aria-label="Next"
        className="
          absolute z-10 flex h-12 w-12 items-center justify-center rounded-full bg-white/10 text-white backdrop-blur
          portrait:bottom-[max(1.5rem,env(safe-area-inset-bottom))] portrait:right-[10%]
          landscape:right-[max(1rem,env(safe-area-inset-right))] landscape:top-1/2 landscape:-translate-y-1/2
        "
      ><ChevronRight className="h-5 w-5" /></button>
    </div>
  );
}

// hooks/usePenDetection.ts
import { useEffect, useState } from 'react';

export function usePenDetection() {
  const [hasPen, setHasPen] = useState(false);

  useEffect(() => {
    const onPointer = (e: PointerEvent) => {
      if (e.pointerType === 'pen') setHasPen(true);
    };
    document.addEventListener('pointerdown', onPointer, { passive: true });
    return () => document.removeEventListener('pointerdown', onPointer);
  }, []);

  return hasPen;
}

