import { useState } from 'react';
import { useReducedMotion, usePrefersReducedData } from '@/hooks/useUserPreferences';

export function MotionAwareGif({ gif, poster, alt }: { gif: string; poster: string; alt: string }) {
  const reducedMotion = useReducedMotion();
  const reducedData = usePrefersReducedData();
