      <img
        src={shouldAnimate ? gif : poster}
        alt={alt}
        className="block rounded"
      />
      {!shouldAnimate && (
        <span
          aria-hidden
          className="absolute inset-0 flex items-center justify-center bg-black/30 group-hover:bg-black/50"
        >
          <span className="rounded-full bg-white p-3 text-black">▶</span>
        </span>
      )}
