'use client';
import { useScrollDirection } from '@/hooks/useScrollDirection'; // from responsive-029
import { useEffect, useState } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function AdaptiveHeader({ logo, nav }: { logo: React.ReactNode; nav: React.ReactNode }) {
  const dir = useScrollDirection();
  const isDesktop = useMediaQuery('(min-width: 1024px)', true);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 100);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const hide = !isDesktop && dir === 'down';
  const compress = isDesktop && scrolled;

  return (
    <header
      className="sticky top-0 z-30 border-b bg-white/95 backdrop-blur transition-[transform,height]"
      style={{
        transform: hide ? 'translateY(-100%)' : 'translateY(0)',
        height: compress ? '3rem' : '4rem',
        paddingTop: 'env(safe-area-inset-top)',
      }}
    >
      <div className="mx-auto max-w-7xl px-4 h-full flex items-center justify-between">
        <div className={compress ? 'scale-90 origin-left transition-transform' : 'transition-transform'}>{logo}</div>
        {nav}
      </div>
    </header>
  );
}

// components/AdaptivePopover.tsx
import { useState, useRef, useEffect } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';

export function AdaptivePopover({ trigger, children }: { trigger: React.ReactNode; children: React.ReactNode }) {
  const bp = useBreakpoint();
  const [open, setOpen] = useState(false);
  const triggerRef = useRef<HTMLDivElement>(null);
  const [pos, setPos] = useState<{ top: number; left: number; placement: 'bottom' | 'top' } | null>(null);

  useEffect(() => {
    if (!open || bp === 'mobile' || !triggerRef.current) return;
    const r = triggerRef.current.getBoundingClientRect();
    const POPOVER_H = 350;
    const POPOVER_W = 300;
    const spaceBelow = window.innerHeight - r.bottom;
    const placement = spaceBelow > POPOVER_H ? 'bottom' : 'top';
    setPos({
      top: placement === 'bottom' ? r.bottom + 4 : r.top - POPOVER_H - 4,
      left: Math.max(8, Math.min(r.left, window.innerWidth - POPOVER_W - 8)),
      placement,
    });
  }, [open, bp]);

  return (
    <>
      <div ref={triggerRef} onClick={() => setOpen(true)}>{trigger}</div>
      {open && bp === 'mobile' && (
        <>
          <div className="fixed inset-0 z-50 bg-black/50" onClick={() => setOpen(false)} />
          <div
            role="dialog"
            aria-modal="true"
            className="fixed inset-x-0 bottom-0 z-50 rounded-t-2xl bg-white shadow-2xl p-4"
            style={{ paddingBottom: 'max(1rem, env(safe-area-inset-bottom))' }}
          >{children}</div>
        </>
      )}
      {open && bp !== 'mobile' && pos && (
        <>
          <div className="fixed inset-0 z-40" onClick={() => setOpen(false)} />
          <div
            role="dialog"
            aria-modal="true"
            className="fixed z-50 w-[300px] rounded-lg border bg-white p-4 shadow-xl"
            style={{ top: pos.top, left: pos.left }}
          >{children}</div>
        </>
      )}
    </>
  );
}

// hooks/useEnvironment.ts
import { useEffect, useState } from 'react';

type Environment = 'safari' | 'in-app-browser' | 'standalone' | 'other';

export function useEnvironment(): Environment {
  const [env, setEnv] = useState<Environment>('other');

  useEffect(() => {
    const ua = navigator.userAgent;
    const inApp = /Instagram|FBAN|FBAV|FB_IAB|TikTok|Twitter|Pinterest|Snapchat|Line/i.test(ua);
    const standalone = window.matchMedia('(display-mode: standalone)').matches;
    if (standalone) setEnv('standalone');
    else if (inApp) setEnv('in-app-browser');
    else if (/Safari/i.test(ua) && !/Chrome|CriOS/i.test(ua)) setEnv('safari');
    else setEnv('other');
  }, []);

  return env;
}

