import { useEnvironment } from '@/hooks/useEnvironment';

export function EnvAwareFeature({ children }: { children: React.ReactNode }) {
  const env = useEnvironment();
  const hasServiceWorker = typeof navigator !== 'undefined' && 'serviceWorker' in navigator;

  return (
    <>
      {env === 'in-app-browser' && (
        <div role="alert" className="bg-yellow-50 border-b border-yellow-200 p-3 text-sm">
          For the best experience, <a href={window.location.href} className="underline font-medium">open in your browser</a>.
        </div>
      )}
      {children}
      {/* Don't attempt to install service worker in webview */}
      {hasServiceWorker && env !== 'in-app-browser' && (
