import { useState } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function CardWithPreview({ summary, fullContent }: { summary: React.ReactNode; fullContent: React.ReactNode }) {
  const canHover = useMediaQuery('(hover: hover) and (pointer: fine)', false);
  const [pinned, setPinned] = useState(false);
  const [hovered, setHovered] = useState(false);
  const show = canHover ? hovered : pinned;

  return (
    <article
      className="relative inline-block"
      onMouseEnter={canHover ? () => setHovered(true) : undefined}
      onMouseLeave={canHover ? () => setHovered(false) : undefined}
