      onBlur={canHover ? () => setHovered(false) : undefined}
    >
      <button
        type="button"
        onClick={canHover ? undefined : () => setPinned((p) => !p)}
        aria-expanded={!canHover ? pinned : undefined}
        className="text-left"
      >{summary}</button>
      {show && (
        <div role={canHover ? 'tooltip' : 'dialog'} className="absolute left-0 top-full z-30 mt-2 w-80 rounded-lg border bg-white p-4 shadow-xl">
          {fullContent}
          {!canHover && (
            <button type="button" onClick={() => setPinned(false)} aria-label="Close preview" className="absolute right-2 top-2 flex h-8 w-8 items-center justify-center text-neutral-500">×</button>
          )}
        </div>
