// components/RichEditor.tsx
import { useEffect, useRef } from 'react';
import { useKeyboardInset } from '@/hooks/useKeyboardInset';

export function RichEditor({ html, onChange }: { html: string; onChange: (h: string) => void }) {
  useKeyboardInset();
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const onSelectionChange = () => {
      const sel = window.getSelection();
      if (!sel || sel.rangeCount === 0) return;
      const range = sel.getRangeAt(0);
      if (!ref.current?.contains(range.startContainer)) return;

      const rect = range.getBoundingClientRect();
      const vv = window.visualViewport;
      if (!vv) return;

      const visibleBottom = vv.offsetTop + vv.height;
      if (rect.bottom > visibleBottom - 60) {
        window.scrollBy({ top: rect.bottom - visibleBottom + 80, behavior: 'smooth' });
      }
    };

    document.addEventListener('selectionchange', onSelectionChange);
    return () => document.removeEventListener('selectionchange', onSelectionChange);
  }, []);

  return (
    <div
      ref={ref}
      contentEditable
      onInput={(e) => onChange((e.target as HTMLElement).innerHTML)}
      role="textbox"
      aria-multiline="true"
      aria-label="Editor"
      className="min-h-40 p-4 outline-none"
      dangerouslySetInnerHTML={{ __html: html }}
      style={{ paddingBottom: 'calc(var(--keyboard-inset, 0px) + 4rem)' }}
    />
  );
}

