// hooks/usePlatform.ts
import { useEffect, useState } from 'react';

export function usePlatform(): 'mac' | 'win' | 'other' {
  const [p, setP] = useState<'mac' | 'win' | 'other'>('other');
  useEffect(() => {
    const ua = navigator.userAgent;
    if (/Mac|iPad|iPhone/i.test(ua)) setP('mac');
    else if (/Win/i.test(ua)) setP('win');
  }, []);
  return p;
}

// components/MenuItemWithShortcut.tsx
import { usePlatform } from '@/hooks/usePlatform';
import { useMediaQuery } from '@/hooks/useMediaQuery';

type Shortcut = { ctrl?: boolean; shift?: boolean; alt?: boolean; key: string };

function formatShortcut(s: Shortcut, platform: 'mac' | 'win' | 'other') {
  const parts: string[] = [];
  if (s.ctrl) parts.push(platform === 'mac' ? '⌘' : 'Ctrl');
  if (s.shift) parts.push(platform === 'mac' ? '⇧' : 'Shift');
  if (s.alt) parts.push(platform === 'mac' ? '⌥' : 'Alt');
  parts.push(s.key.toUpperCase());
  return parts.join(platform === 'mac' ? '' : '+');
}

export function MenuItemWithShortcut({ label, shortcut, onClick }: { label: string; shortcut?: Shortcut; onClick: () => void }) {
  const platform = usePlatform();
  const hasKeyboard = useMediaQuery('(any-pointer: fine)', false);

  return (
    <button type="button" onClick={onClick} className="flex w-full items-center justify-between px-3 py-2 min-h-11 text-left hover:bg-neutral-100">
      <span>{label}</span>
      {shortcut && hasKeyboard && (
        <kbd className="text-xs font-mono text-neutral-500">{formatShortcut(shortcut, platform)}</kbd>
      )}
    </button>
  );
}

