// components/EditableCell.tsx
import { useState, useRef, useEffect } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function EditableCell({ value, onChange }: { value: string; onChange: (v: string) => void }) {
  const isTouch = useMediaQuery('(pointer: coarse)', true);
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (editing) inputRef.current?.focus();
  }, [editing]);

  const commit = () => { onChange(draft); setEditing(false); };
  const cancel = () => { setDraft(value); setEditing(false); };

  if (editing) {
    return (
      <input
        ref={inputRef}
        type="text"
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onBlur={commit}
        onKeyDown={(e) => {
          if (e.key === 'Enter') commit();
          if (e.key === 'Escape') cancel();
        }}
        className="w-full h-full px-2 outline-2 outline-blue-500 bg-white text-base"
      />
    );
  }

  return (
    <div
      role="button"
      tabIndex={0}
      onClick={isTouch ? () => setEditing(true) : undefined}
      onDoubleClick={!isTouch ? () => setEditing(true) : undefined}
      onKeyDown={(e) => { if (e.key === 'Enter' || e.key === 'F2') setEditing(true); }}
      className="
        h-full min-h-11 px-2 py-1 border
        cursor-cell select-none
        hover:bg-blue-50 focus-visible:outline-2 focus-visible:outline-blue-500
      "
    >{value}</div>
  );
}

